mapper.select:
select r.*, c.course_name, u.real_name as artist_name from media_resource r left join repertoire_info c on r.course_id = c.id left join sys_user u on r.artist_id = u.id
and r.schedule_id = #{scheduleId}
and r.artist_id = #{artistId}
and r.title like concat('%', #{keyword}, '%')
order by r.id desc

select r.*, c.course_name, u.real_name as artist_name from media_resource r inner join booking_record cs on r.schedule_id = cs.schedule_id left join repertoire_info c on r.course_id = c.id left join sys_user u on r.artist_id = u.id where cs.member_id = #{memberId}
and r.title like concat('%', #{keyword}, '%')
order by r.id desc

mapper.update:
update media_resource
schedule_id = #{scheduleId}, course_id = #{courseId}, title = #{title}, resource_type = #{resourceType}, resource_url = #{resourceUrl}, content_desc = #{contentDesc}, status = #{status},
where id = #{id}
